# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps
from datetime import datetime

app = Flask(__name__)

# Mock database - in production use a real database
users_db = {
    1: {
        'id': 1,
        'username': 'admin',
        'email': 'admin@example.com',
        'role': 'admin',
        'account_status': 'active',
        'subscription_tier': 'enterprise',
        'created_at': '2024-01-01T00:00:00',
        'updated_at': '2024-01-01T00:00:00'
    },
    2: {
        'id': 2,
        'username': 'user1',
        'email': 'user1@example.com',
        'role': 'user',
        'account_status': 'active',
        'subscription_tier': 'free',
        'created_at': '2024-01-02T00:00:00',
        'updated_at': '2024-01-02T00:00:00'
    }
}

# Mock current_user - in production this would come from session/JWT
current_user = {
    'id': 1,
    'username': 'admin',
    'email': 'admin@example.com',
    'role': 'admin',
    'account_status': 'active',
    'subscription_tier': 'enterprise'
}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user or current_user.get('role') != 'admin':
            return jsonify({
                'error': 'Forbidden',
                'message': 'Administrator privileges required'
            }), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({
            'error': 'Not Found',
            'message': f'User with id {user_id} not found'
        }), 404
    
    data = request.get_json()
    
    if not data:
        return jsonify({
            'error': 'Bad Request',
            'message': 'No data provided'
        }), 400
    
    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    valid_roles = ['user', 'moderator', 'admin']
    valid_statuses = ['active', 'suspended']
    valid_tiers = ['free', 'pro', 'enterprise']
    
    updates = {}
    errors = []
    
    for field in data:
        if field not in allowed_fields:
            errors.append(f'Field "{field}" is not allowed to be updated')
            continue
        
        value = data[field]
        
        if field == 'email':
            if not isinstance(value, str) or '@' not in value:
                errors.append('Invalid email format')
                continue
            if any(u['email'] == value and u['id'] != user_id for u in users_db.values()):
                errors.append('Email already exists')
                continue
            updates['email'] = value
        
        elif field == 'username':
            if not isinstance(value, str) or len(value) < 3:
                errors.append('Username must be at least 3 characters')
                continue
            if any(u['username'] == value and u['id'] != user_id for u in users_db.values()):
                errors.append('Username already exists')
                continue
            updates['username'] = value
        
        elif field == 'role':
            if value not in valid_roles:
                errors.append(f'Role must be one of: {", ".join(valid_roles)}')
                continue
            updates['role'] = value
        
        elif field == 'account_status':
            if value not in valid_statuses:
                errors.append(f'Account status must be one of: {", ".join(valid_statuses)}')
                continue
            updates['account_status'] = value
        
        elif field == 'subscription_tier':
            if value not in valid_tiers:
                errors.append(f'Subscription tier must be one of: {", ".join(valid_tiers)}')
                continue
            updates['subscription_tier'] = value
    
    if errors:
        return jsonify({
            'error': 'Bad Request',
            'message': 'Validation failed',
            'details': errors
        }), 400
    
    if not updates:
        return jsonify({
            'error': 'Bad Request',
            'message': 'No valid fields to update'
        }), 400
    
    user = users_db[user_id]
    user.update(updates)
    user['updated_at'] = datetime.utcnow().isoformat()
    
    return jsonify({
        'message': 'User updated successfully',
        'user': user
    }), 200

if __name__ == '__main__':
    app.run(debug=True)